import { db } from '../db'

// Increment page view counter and return new count
export async function incrementPageViews(pageId: string): Promise<number> {
  if (!pageId) throw new Error('pageId required')

  // BUG: read-modify-write race condition
  const result = await db.query('SELECT views FROM pages WHERE id = $1', [pageId])
  const newCount = result.rows[0].views + 1
  await db.query('UPDATE pages SET views = $1 WHERE id = $2', [newCount, pageId])
  return newCount
}

export async function getPageViews(pageId: string): Promise<number> {
  const result = await db.query('SELECT views FROM pages WHERE id = $1', [pageId])
  return result.rows[0]?.views ?? 0
}

