import { db } from '../db'
import type { Request, Response } from 'express'

export async function listProductsWithCategories(_req: Request, res: Response) {
  // BUG: N+1 query — 1 query for products + 1 per product for category
  const products = await db.query('SELECT * FROM products LIMIT 50')
  for (const product of products.rows) {
    const cat = await db.query('SELECT name FROM categories WHERE id = $1', [product.category_id])
    product.category = cat.rows[0]?.name
  }
  return res.json(products.rows)
}

export async function getProduct(req: Request, res: Response) {
  const result = await db.query(
    'SELECT p.*, c.name as category FROM products p JOIN categories c ON p.category_id = c.id WHERE p.id = $1',
    [req.params.id]
  )
  return res.json(result.rows[0])
}

