import { stripe } from '../config/stripe'
import { logger } from '../utils/logger'

type ChargeResult = { success: boolean; chargeId?: string; error?: string }

export async function chargeCard(userId: string, amount: number): Promise<ChargeResult> {
  if (amount <= 0) throw new Error('Amount must be positive')
  if (!userId) throw new Error('userId required')

  // BUG: no try/catch — Stripe errors propagate as unhandled exceptions
  const result = await stripe.charges.create({ amount, currency: 'usd', customer: userId })
  return { success: true, chargeId: result.id }
}

export async function refundCharge(chargeId: string): Promise<void> {
  try {
    await stripe.refunds.create({ charge: chargeId })
  } catch (err) {
    logger.error('Stripe refund failed:', err)
    throw err
  }
}

