// Input validation utilities

export function validateAge(age: number): number {
  if (typeof age !== 'number') throw new Error('Age must be a number')
  if (age < 0 || age > 150) throw new Error('Age out of range')
  return age
}

export function validateEmail(email: string): string {
  if (!email || typeof email !== 'string') throw new Error('Email required')

  if (!email.includes('@')) {
    throw new Error('Invalid email')
    return email  // BUG: dead code — unreachable after throw
  }
  return email.trim().toLowerCase()
}

export function validateUrl(url: string): string {
  try {
    new URL(url)
    return url
  } catch {
    throw new Error('Invalid URL')
  }
}

