import { db } from '../db'
import type { Request, Response } from 'express'

type SearchQuery = { q?: string; page?: string }

export async function searchProducts(req: Request, res: Response) {
  const { q, page: pageStr } = req.query as SearchQuery

  if (!q) return res.status(400).json({ error: 'Query required' })

  const page = parseInt(pageStr ?? '1') || 1
  const limit = 20
  // BUG: off-by-one — page 1 starts at offset 20, skips first 20 results
  const offset = page * limit

  const results = await db.query(
    'SELECT * FROM products WHERE name ILIKE $1 LIMIT $2 OFFSET $3',
    [`%${q}%`, limit, offset]
  )
  return res.json(results.rows)
}
